from collections import defaultdict

def kosaraju(graph):
    """
    Finds Strongly Connected Components (SCCs) in a directed graph using Kosaraju's algorithm.

    Args:
        graph: A dictionary representing the directed graph.
               Keys are nodes, values are lists of adjacent nodes (e.g., {0: [1, 2], 1: [3]}).

    Returns:
        A list of lists, where each inner list represents a Strongly Connected Component.
    """

    # Step 1: First DFS to determine finishing times
    visited = set()
    finish_order = []  # Stores nodes in decreasing order of finishing times

    def dfs1(u):
        visited.add(u)
        for v in graph.get(u, []):
            if v not in visited:
                dfs1(v)
        finish_order.append(u)

    # Collect all unique nodes in the graph
    all_nodes = set(graph.keys())
    for u in graph:
        for v in graph[u]:
            all_nodes.add(v)

    for node in all_nodes:
        if node not in visited:
            dfs1(node)

    # Step 2: Create the transpose graph (G_T)
    graph_t = defaultdict(list)
    for u in graph:
        for v in graph[u]:
            graph_t[v].append(u)

    # Ensure all nodes from the original graph are keys in graph_t, even if they have no incoming edges
    for node in all_nodes:
        if node not in graph_t:
            graph_t[node] = []


    # Step 3: Second DFS on the transpose graph using the finishing order
    visited = set()
    sccs = []

    def dfs2(u, current_scc):
        visited.add(u)
        current_scc.append(u)
        for v in graph_t.get(u, []):
            if v not in visited:
                dfs2(v, current_scc)

    # Process nodes in reverse order of finishing times
    for node in reversed(finish_order):
        if node not in visited:
            current_scc = []
            dfs2(node, current_scc)
            sccs.append(current_scc)

    return sccs
